evaluators.evaluation_logic:
const checkpoints = [];
const favoritesRaw = localStorage.getItem('favorite_articles');
const articlesRaw = localStorage.getItem('articles');
let favorites = [];
let articles = [];
try { favorites = favoritesRaw ? JSON.parse(favoritesRaw) : []; } catch (e) { favorites = []; }
try { articles = articlesRaw ? JSON.parse(articlesRaw) : []; } catch (e) { articles = []; }

const qualifyingFavorites = favorites.filter(fav => {
  const article = articles.find(a => a.id === fav.article_id);
  if (!article) return false;
  return (
    article.category === 'safety_basics' &&
    article.difficulty_level === 'beginner' &&
    (article.read_time_minutes || 0) <= 8 &&
    (article.rating || 0) >= 4.0
  );
});

[1, 2, 3].forEach((n, idx) => {
  const weight = idx < 2 ? 0.33 : 0.34; // 0.33 + 0.33 + 0.34 = 1.0
  checkpoints.push({ passed: qualifyingFavorites.length >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const checklists = JSON.parse(localStorage.getItem('checklists') || '[]');
const sections = JSON.parse(localStorage.getItem('checklist_sections') || '[]');
const items = JSON.parse(localStorage.getItem('checklist_items') || '[]');
const progressAll = JSON.parse(localStorage.getItem('checklist_progress') || '[]');

const targetChecklist = checklists.find(c =>
  c.boat_type === 'pontoon' &&
  c.trip_length === 'day_trip_4_8_hours' &&
  c.passenger_range === 'passengers_4_6'
);

let completedFirstFiveCount = 0;

if (targetChecklist) {
  const sectionsForChecklist = sections
    .filter(s => s.checklist_id === targetChecklist.id)
    .sort((a, b) => (a.order || 0) - (b.order || 0));

  const orderedItemIds = [];
  sectionsForChecklist.forEach(sec => {
    const sectionItems = items
      .filter(i => i.checklist_id === targetChecklist.id && i.section_id === sec.id)
      .sort((a, b) => (a.order || 0) - (b.order || 0));
    sectionItems.forEach(it => orderedItemIds.push(it.id));
  });

  const firstFiveIds = orderedItemIds.slice(0, 5);
  const progress = progressAll.find(p => p.checklist_id === targetChecklist.id);

  if (progress && Array.isArray(progress.completed_item_ids)) {
    const completedSet = new Set(progress.completed_item_ids);
    completedFirstFiveCount = firstFiveIds.filter(id => completedSet.has(id)).length;
  }
}

// Award credit only for completing the correct first five checklist items on the correct checklist
checkpoints.push({ passed: completedFirstFiveCount >= 1, weight: 0.3 });
checkpoints.push({ passed: completedFirstFiveCount >= 3, weight: 0.3 });
checkpoints.push({ passed: completedFirstFiveCount >= 5, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function safeParse(objStr) {
  try { return objStr && objStr !== 'null' ? JSON.parse(objStr) : null; } catch (e) { return null; }
}

function isApprox(value, target, tolerance) {
  if (typeof value !== 'number') return false;
  return Math.abs(value - target) <= tolerance;
}

const last = safeParse(localStorage.getItem('lastBoatCapacityCalculation'));
const tripPlans = JSON.parse(localStorage.getItem('trip_plans') || '[]');

let lastMatchesScenario = false;
if (last) {
  const lenOk = isApprox(last.boat_length_ft, 18, 1);
  const widthOk = isApprox(last.boat_width_ft, 7, 0.5);
  const typeStr = (last.boat_type || '').toLowerCase();
  const typeOk = last.boat_type === 'open_motorboat' || typeStr.includes('open') && typeStr.includes('motorboat');
  const waterStr = (last.water_type || '').toLowerCase();
  const waterOk = last.water_type === 'inland_lake_river' || waterStr.includes('inland');
  lastMatchesScenario = lenOk && widthOk && typeOk && waterOk;
}

const candidatePlans = tripPlans.filter(p => {
  const lenOk = isApprox(p.boat_length_ft, 18, 1);
  const widthOk = isApprox(p.boat_width_ft, 7, 0.5);
  const typeStr = (p.boat_type || '').toLowerCase();
  const typeOk = p.boat_type === 'open_motorboat' || (typeStr.includes('open') && typeStr.includes('motorboat'));
  const waterStr = (p.water_type || '').toLowerCase();
  const waterOk = p.water_type === 'inland_lake_river' || waterStr.includes('inland');
  const passengersOk = p.planned_passenger_count === 6;
  return lenOk && widthOk && typeOk && waterOk && passengersOk;
});

let hasPlanFromLast = false;
if (last && lastMatchesScenario) {
  hasPlanFromLast = candidatePlans.some(p =>
    p.boat_length_ft === last.boat_length_ft &&
    p.boat_width_ft === last.boat_width_ft &&
    p.boat_type === last.boat_type &&
    p.water_type === last.water_type &&
    p.calculated_max_passengers === last.calculated_max_passengers
  );
}

// CP1 (0.4): Last capacity calculation matches an ~18×7 ft open motorboat on inland water
checkpoints.push({ passed: lastMatchesScenario, weight: 0.4 });
// CP2 (0.3): There is a saved trip plan for this scenario with planned_passenger_count === 6
checkpoints.push({ passed: candidatePlans.length >= 1, weight: 0.3 });
// CP3 (0.3): At least one such trip plan is directly consistent with the last capacity calculation
checkpoints.push({ passed: hasPlanFromLast, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const printId = localStorage.getItem('task4_lastPrintArticleId');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');

const query = 'thunderstorm emergency';
const fromDate = new Date('2022-01-01T00:00:00Z');

const candidates = articles.filter(a => {
  if (!a) return false;
  if (a.category !== 'safety_basics') return false;
  if (a.boat_size_category && a.boat_size_category !== 'up_to_26_ft') return false;
  const pubDate = a.publish_date ? new Date(a.publish_date) : null;
  if (pubDate && pubDate < fromDate) return false;
  const haystack = [a.title || '', a.summary || '', a.content || ''].join(' ').toLowerCase();
  return haystack.includes(query);
});

let newestArticle = null;
if (candidates.length > 0) {
  newestArticle = candidates.reduce((latest, a) => {
    const d = a.publish_date ? new Date(a.publish_date) : new Date(0);
    if (!latest) return a;
    const ld = latest.publish_date ? new Date(latest.publish_date) : new Date(0);
    return d > ld ? a : latest;
  }, null);
}

const printedArticle = articles.find(a => a.id === printId);
const printedQualifies = !!(printedArticle && candidates.some(a => a.id === printedArticle.id));
const printedIsNewest = !!(printedArticle && newestArticle && printedArticle.id === newestArticle.id);

// CP1 (0.5): User opened print view for a qualifying thunderstorm emergency article for boats up to 26 ft from 2022+
checkpoints.push({ passed: printedQualifies, weight: 0.5 });
// CP2 (0.5): The printed article is the newest among all qualifying articles
checkpoints.push({ passed: printedIsNewest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const courses = JSON.parse(localStorage.getItem('courses') || '[]');
const entries = JSON.parse(localStorage.getItem('training_plan_entries') || '[]');

const qualifyingCourses = courses.filter(c => (
  c.type === 'basic_boating_safety' &&
  (c.price || 0) <= 100 &&
  (c.distance_miles || 0) <= 25 &&
  c.level === 'beginner'
));

const cheapestPrice = qualifyingCourses.length
  ? Math.min(...qualifyingCourses.map(c => c.price || 0))
  : null;

function isJune2024(entry) {
  if (!entry) return false;
  const label = (entry.planned_start_month_label || '').toLowerCase();
  if (label.includes('june') && label.includes('2024')) return true;
  if (entry.planned_start_month_date) {
    const d = new Date(entry.planned_start_month_date);
    if (!isNaN(d.getTime()) && d.getUTCFullYear() === 2024 && d.getUTCMonth() === 5) {
      // UTCMonth 5 = June
      return true;
    }
  }
  return false;
}

const qualifyingEntries = entries.filter(e => {
  const course = courses.find(c => c.id === e.course_id);
  if (!course) return false;
  const isQualCourse = qualifyingCourses.some(qc => qc.id === course.id);
  return isQualCourse && isJune2024(e);
});

const hasAnyQualEntry = qualifyingEntries.length > 0;

let hasCheapestQualEntry = false;
if (cheapestPrice != null) {
  hasCheapestQualEntry = qualifyingEntries.some(e => {
    const course = courses.find(c => c.id === e.course_id);
    return course && (course.price || 0) === cheapestPrice;
  });
}

// CP1 (0.4): User added at least one qualifying beginner basic safety course within 25 miles and ≤$100 with a June 2024 start month
checkpoints.push({ passed: hasAnyQualEntry, weight: 0.4 });
// CP2 (0.6): At least one such entry is for the cheapest qualifying course
checkpoints.push({ passed: hasCheapestQualEntry, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const schedules = JSON.parse(localStorage.getItem('engine_maintenance_schedules') || '[]');
const tasks = JSON.parse(localStorage.getItem('engine_maintenance_tasks') || '[]');

let preview = null;
try {
  const raw = localStorage.getItem('lastGeneratedMaintenanceSchedule');
  preview = raw && raw !== 'null' ? JSON.parse(raw) : null;
} catch (e) {
  preview = null;
}

function isTwoStrokeOutboard(value) {
  if (!value) return false;
  const v = String(value).toLowerCase();
  return v.includes('two_stroke_outboard') ||
         (v.includes('2-stroke') && v.includes('outboard')) ||
         (v.includes('2 stroke') && v.includes('outboard'));
}

function isUsedMonthly(value) {
  if (!value) return false;
  const v = String(value).toLowerCase();
  return v.includes('used_monthly') || v.includes('used monthly');
}

function isSaltwater(value) {
  if (!value) return false;
  return String(value).toLowerCase().includes('saltwater');
}

function isEvery1Month(value) {
  if (!value) return false;
  const v = String(value).toLowerCase();
  return v === 'every_1_month' || v.includes('1 month');
}

function isStartJuly2024(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  // Accept any date in July 2024
  return d.getUTCFullYear() === 2024 && d.getUTCMonth() === 6; // July
}

const matchingSchedules = schedules.filter(s => (
  isTwoStrokeOutboard(s.engine_type) &&
  isUsedMonthly(s.usage_frequency) &&
  isSaltwater(s.water_type) &&
  isEvery1Month(s.reminder_frequency) &&
  isStartJuly2024(s.start_date)
));

const hasSavedScheduleWithTasks = matchingSchedules.some(s =>
  tasks.some(t => t.schedule_id === s.id)
);

let previewMatches = false;
if (preview && preview.schedule) {
  const s = preview.schedule;
  previewMatches = (
    isTwoStrokeOutboard(s.engine_type) &&
    isUsedMonthly(s.usage_frequency) &&
    isSaltwater(s.water_type) &&
    isEvery1Month(s.reminder_frequency) &&
    isStartJuly2024(s.start_date)
  );
}

// CP1 (0.6): There is a saved engine maintenance schedule matching the criteria with at least one associated task
checkpoints.push({ passed: hasSavedScheduleWithTasks, weight: 0.6 });
// CP2 (0.4): The last generated maintenance schedule (preview cache) also matches the same criteria
checkpoints.push({ passed: previewMatches, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const learningPaths = JSON.parse(localStorage.getItem('learning_paths') || '[]');
const learningPathItems = JSON.parse(localStorage.getItem('learning_path_items') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');

const learningPath = learningPaths[0] || null;
let itemsWithArticles = [];

if (learningPath) {
  const itemsForPath = learningPathItems.filter(i => i.learning_path_id === learningPath.id);
  itemsWithArticles = itemsForPath
    .map(item => {
      const article = articles.find(a => a.id === item.article_id) || null;
      return { item, article };
    })
    .filter(x => x.article && x.article.category === 'how_to_guides');
}

const nightStepExists = itemsWithArticles.some(x => {
  const a = x.article;
  const tabOk = (a.category_tab || '').toLowerCase() === 'navigation';
  const text = (
    (a.title || '') + ' ' +
    (a.summary || '') + ' ' +
    (a.content || '') + ' ' +
    (Array.isArray(a.tags) ? a.tags.join(' ') : '')
  ).toLowerCase();
  const hasNight = text.includes('night') || text.includes('after dark');
  return tabOk && hasNight;
});

const anchoringStepExists = itemsWithArticles.some(x => {
  const a = x.article;
  const tabOk = (a.category_tab || '').toLowerCase() === 'anchoring_mooring';
  const title = (a.title || '').toLowerCase();
  const diff = (a.difficulty_level || '').toLowerCase();
  const hasBeginner = title.includes('beginner') || diff === 'beginner';
  return tabOk && hasBeginner;
});

const vhfStepExists = itemsWithArticles.some(x => {
  const a = x.article;
  const tabOk = (a.category_tab || '').toLowerCase() === 'communication_electronics';
  const text = (
    (a.title || '') + ' ' +
    (a.summary || '') + ' ' +
    (a.content || '') + ' ' +
    (Array.isArray(a.tags) ? a.tags.join(' ') : '')
  ).toLowerCase();
  const hasVhf = text.includes('vhf');
  return tabOk && hasVhf;
});

// CP1 (0.4): Night navigation article from Navigation tab in learning path
checkpoints.push({ passed: nightStepExists, weight: 0.4 });
// CP2 (0.3): Beginner anchoring article from Anchoring & Mooring tab in learning path
checkpoints.push({ passed: anchoringStepExists, weight: 0.3 });
// CP3 (0.3): VHF radio article from Communication & Electronics tab in learning path
checkpoints.push({ passed: vhfStepExists, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const terms = JSON.parse(localStorage.getItem('glossary_terms') || '[]');
const studyItems = JSON.parse(localStorage.getItem('study_list_items') || '[]');

const qualifyingStudyItems = studyItems.filter(si => {
  const term = terms.find(t => t.id === si.term_id);
  return term && term.category === 'radio_distress_calls';
});

[1, 2, 3].forEach((n, idx) => {
  const weight = idx < 2 ? 0.33 : 0.34; // 0.33 + 0.33 + 0.34 = 1.0
  checkpoints.push({ passed: qualifyingStudyItems.length >= n, weight });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
